#include <bits/stdc++.h>
using namespace std;

const int N=2e6+10;

int n,m;
int head[N],ver[N],nxt[N],tot;
int dfn[N],low[N],num,stk[N],top,cnt,c[N];
bool ins[N];

void add(int x,int y){
    ver[++tot]=y,nxt[tot]=head[x],head[x]=tot;
}

void tarjan(int x){
    dfn[x]=low[x]=++num;
    stk[++top]=x,ins[x]=1;
    for(int i=head[x],y;i;i=nxt[i])
        if(!dfn[y=ver[i]]){
            tarjan(y);
            low[x]=min(low[x],low[y]);
        }else if(ins[y])
            low[x]=min(low[x],dfn[y]);
    if(dfn[x]==low[x]){
        int z;
        cnt++;
        do{
            z=stk[top--],ins[z]=0,c[z]=cnt;
        }while(z!=x);
    }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,x,y,a,b;i<=m;i++){
        scanf("%d%d%d%d",&x,&a,&y,&b);
        add(x+(a^1)*n,y+b*n);
        add(y+(b^1)*n,x+a*n);
    }
    for(int i=1;i<=2*n;i++)
        if(!dfn[i])
            tarjan(i);
    for(int i=1;i<=n;i++)
        if(c[i]==c[i+n]){
            printf("IMPOSSIBLE");
            return 0;
        }
    puts("POSSIBLE");
    for(int i=1;i<=n;i++)
        printf("%d ",(c[i]>c[i+n]));
    return 0;
}
